Bash("D:/mysql-8.0.46-winx64/mysql-8.0.46-winx64/bin/mysql.exe" -u root -p123456 railway_system -e "
SELECT '=== 车次类型统计 ===' as info;
SELECT CASE train_type WHEN 1 THEN '高铁\(G\)' WHEN 2 THEN '动车\(D\)' WHEN 3 THEN '城际\(C\)' ELSE '其他' END as type, COUNT\(*\) as count FROM trains GROUP BY train_type;

SELECT '=== 示例车次 ===' as info;
SELECT train_code, start_station_name, end_station_name, start_time, end_time, total_time FROM trains LIMIT 5;

SELECT '=== G开头高铁车次 ===' as info;
SELECT train_code, start_station_name, end_station_name FROM trains WHERE train_code LIKE 'G%' LIMIT 5;

SELECT '=== D开头动车车次 ===' as info;
SELECT train_code, start_station_name, end_station_name FROM trains WHERE train_code LIKE 'D%' LIMIT 5;

SELECT '=== C开头城际车次 ===' as info;
SELECT train_code, start_station_name, end_station_name FROM trains WHERE train_code LIKE 'C%' LIMIT 5;
")

Bash("D:/mysql-8.0.46-winx64/mysql-8.0.46-winx64/bin/mysql.exe" -u root -p123456 railway_system -e "
SELECT '=== 时刻表示例：G1次列车 ===' as info;
SELECT ts.stop_order, ts.station_name, ts.arrive_time, ts.depart_time, ts.stop_duration, ts.is_start, ts.is_end
FROM train_stops ts
JOIN trains t ON ts.train_id = t.id
WHERE t.train_code = 'G1'
ORDER BY ts.stop_order;

SELECT '=== 时刻表示例：D1次列车 ===' as info;
SELECT ts.stop_order, ts.station_name, ts.arrive_time, ts.depart_time, ts.stop_duration, ts.is_start, ts.is_end
FROM train_stops ts
JOIN trains t ON ts.train_id = t.id
WHERE t.train_code = 'D1'
ORDER BY ts.stop_order;

SELECT '=== 按车次统计停靠站数量 ===' as info;
SELECT t.train_code, COUNT\(*\) as stops FROM train_stops ts
JOIN trains t ON ts.train_id = t.id
GROUP BY t.train_code
ORDER BY stops DESC
LIMIT 10;
")
